const first = $input.first();
if (first.json?.error) {
  throw new Error(`Article queue read failed: ${first.json.error}`);
}

// Read binary using n8n helper (supports filesystem-v2 mode)
let content = '';
try {
  const binary = first.binary;
  const key = Object.keys(binary || {})[0] || 'data';
  if (binary && binary[key]) {
    const buf = await this.helpers.getBinaryDataBuffer(0, key);
    content = buf.toString('utf-8');
  }
} catch (e) {}

// Strip frontmatter
content = content.replace(/^---[\s\S]*?---\s*/m, '').trim();

if (!content) {
  return [{ json: { hasUrls: false, urls: [] } }];
}

// Parse URLs — supports bare URLs, Markdown links [text](url), autolinks <url>
const lines = content.split('\n').filter(l => l.trim());
const urls = [];
const seen = new Set();

for (const line of lines) {
  let trimmed = line.trim();
  if (!trimmed || trimmed.startsWith('#')) continue;

  // Strip leading bullet markers
  trimmed = trimmed.replace(/^[-*+]\s+/, '');

  // Split on context separator
  const parts = trimmed.split(' — ');
  let urlPart = parts[0].trim();
  const context = parts.length > 1 ? parts.slice(1).join(' — ').trim() : '';

  let url = null;

  // Try Markdown link: [text](url)
  const mdMatch = urlPart.match(/\[.*?\]\((https?:\/\/[^)]+)\)/);
  if (mdMatch) {
    url = mdMatch[1];
  }
  // Try autolink: <url>
  if (!url) {
    const autoMatch = urlPart.match(/<(https?:\/\/[^>]+)>/);
    if (autoMatch) url = autoMatch[1];
  }
  // Try bare URL
  if (!url && (urlPart.startsWith('http://') || urlPart.startsWith('https://'))) {
    url = urlPart;
  }
  // Last resort: find URL anywhere in the line
  if (!url) {
    const anyMatch = urlPart.match(/(https?:\/\/[^\s)>]+)/);
    if (anyMatch) url = anyMatch[1];
  }

  if (url && !seen.has(url)) {
    seen.add(url);
    urls.push({ url, context });
  }
}

if (urls.length === 0) {
  return [{ json: { hasUrls: false, url: null, context: '', urlCount: 0 } }];
}
return urls.map(u => ({ json: { hasUrls: true, url: u.url, context: u.context, urlCount: urls.length } }));

// Each item from the loop is already a single {url, context} object
// Pass it through cleanly for Fetch Page
const item = $input.first().json;
return [{ json: { url: item.url, context: item.context || '' } }];

const input = $input.first();
let text = '';

try {
  // Get response body as text
  const body = input.json.data || input.json.body || '';

  // Strip HTML tags, scripts, styles
  text = body
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<nav[\s\S]*?<\/nav>/gi, '')
    .replace(/<footer[\s\S]*?<\/footer>/gi, '')
    .replace(/<header[\s\S]*?<\/header>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ')
    .trim();

  // Limit to ~3000 chars to keep token usage low
  if (text.length > 3000) {
    text = text.substring(0, 3000) + '... [truncated]';
  }
} catch (e) {
  text = 'Failed to extract text from page.';
}

const urlData = $('Loop: Each URL').first().json;
return [{ json: { extractedText: text, url: urlData.url, context: urlData.context } }];

const input = $input.first().json;
const text = input.extractedText || '';
const url = input.url || '';
const context = input.context || '';

const SYSTEM = 'You are the AI Brain for Aaron's Life Operating System. You process personal knowledge management content and return structured JSON only.

CONTEXT:
- 8 life domains: faith, family, business, consulting, work, health, home, personal
- Task format: - [ ] Description [area:: X] [priority:: A/B/C] [due:: YYYY-MM-DD]
- Priority A = needle-mover, B = important, C = nice-to-have

RULES:
- Return valid JSON only. No markdown fences. No explanatory text.
- Summaries are 3-4 sentences max.';

const USER = `TASK: Summarize this article content.

Return JSON:
{"results": {"title": "string", "summary": "3-4 sentence summary", "key_takeaways": ["takeaway1", "takeaway2", "takeaway3"], "area": "string", "needle_mover": true|false, "action_items": [{"task": "string", "area": "string", "priority": "A|B|C", "due": "YYYY-MM-DD|null"}]}}

SOURCE URL: ${url}
${context ? 'CONTEXT: ' + context + '
' : ''}
ARTICLE TEXT:
${text}`;

return [{ json: { systemPrompt: SYSTEM, userMessage: USER } }];

const input = $input.first().json;
try {
  const content = input.choices[0].message.content;
  // Strip markdown fences if present (some models add them)
  const cleaned = content.replace(/^```json\n?/i, '').replace(/\n?```$/i, '').trim();
  const parsed = JSON.parse(cleaned);
  return [{ json: { success: true, ...parsed, source: 'openrouter' } }];
} catch (e) {
  return [{ json: { success: false, error: 'Failed to parse AI response: ' + e.message, raw: JSON.stringify(input).substring(0, 500) } }];
}

const input = $input.first().json;
const r = input.results || input;
const BUCKET = 'obsidian-vault';
const PREFIX = '';

const AREA_FOLDER_MAP = {
  faith: '30_Knowledge Library/Bible Studies & Notes',
  family: '20_Domains (Life and Work)/Personal/Family',
  business: '20_Domains (Life and Work)/Personal/Business Ideas & Projects',
  consulting: '20_Domains (Life and Work)/Career/Consulting',
  work: '20_Domains (Life and Work)/Career/Parallon',
  health: '30_Knowledge Library/Biohacking',
  home: '20_Domains (Life and Work)/Personal/Home',
  personal: '20_Domains (Life and Work)/Personal'
};

const area = r.area || 'personal';
const folder = AREA_FOLDER_MAP[area] || AREA_FOLDER_MAP.personal;
const slug = (r.title || 'article').toLowerCase().replace(/[^a-z0-9]+/g, '-').substring(0, 50);

const TZ = 'America/Chicago';
const now = new Date();
const fmt = (opts) => new Intl.DateTimeFormat('en-US', { timeZone: TZ, ...opts });
const y = parseInt(fmt({ year: 'numeric' }).format(now));
const m = fmt({ month: '2-digit' }).format(now);
const d = fmt({ day: '2-digit' }).format(now);
const dateStr = `${y}-${m}-${d}`;

// Get original URL from the extract-text node context
let sourceUrl = '';
try {
  sourceUrl = $('Extract Text').first().json.url || '';
} catch (e) {}

let noteContent = `---\ntype: article-note\nsource_url: ${sourceUrl}\ndate_captured: ${dateStr}\narea: ${area}\nneedle_mover: ${r.needle_mover || false}\n---\n\n# ${r.title || 'Untitled Article'}\n\n## Summary\n${r.summary || 'No summary available.'}\n\n## Key Takeaways\n`;

if (r.key_takeaways && r.key_takeaways.length > 0) {
  r.key_takeaways.forEach(t => { noteContent += `- ${t}\n`; });
} else {
  noteContent += '- No takeaways extracted.\n';
}

// Action items as inline tasks
if (r.action_items && r.action_items.length > 0) {
  noteContent += '\n## Action Items\n';
  r.action_items.forEach(a => {
    const due = a.due ? ` [due:: ${a.due}]` : '';
    noteContent += `- [ ] ${a.task} [area:: ${a.area || area}] [priority:: ${a.priority || 'B'}]${due}\n`;
  });
}

return [{ json: {
  bucket: BUCKET,
  fileKey: `${folder}/${dateStr}-${slug}.md`,
  content: noteContent,
  actionItems: r.action_items || [],
  title: r.title
} }];

// Convert string content to base64 binary for S3 upload
const item = $input.item.json;
const contentStr = item.content || '';
const base64 = Buffer.from(contentStr, 'utf-8').toString('base64');

return [{
  json: { fileKey: item.fileKey, label: item.title || 'article' },
  binary: {
    data: {
      data: base64,
      mimeType: 'text/markdown',
      fileName: item.fileKey.split('/').pop() || 'article.md'
    }
  }
}];

// After all URLs processed, clear the articles-to-process.md file
const BUCKET = 'obsidian-vault';
const PREFIX = '';

const clearedContent = `---\ntype: article-queue\n---\n\n`;

return [{ json: {
  bucket: BUCKET,
  fileKey: `00_Inbox/articles-to-process.md`,
  content: clearedContent,
  label: 'Clear article queue'
} }];

// Convert string content to base64 binary for S3 upload
const item = $input.item.json;
const contentStr = item.content || '';
const base64 = Buffer.from(contentStr, 'utf-8').toString('base64');

return [{
  json: { fileKey: item.fileKey, label: item.label },
  binary: {
    data: {
      data: base64,
      mimeType: 'text/markdown',
      fileName: item.fileKey.split('/').pop() || 'file.md'
    }
  }
}];
